<template><PageHeader title="用户管理"><el-input v-model="query" placeholder="搜索昵称/手机号" style="width:260px"/></PageHeader><div class="panel"><el-table :data="filtered"><el-table-column prop="id" label="ID"/><el-table-column prop="nickname" label="昵称"/><el-table-column prop="phone" label="手机号"/><el-table-column prop="subscriptionLevel" label="套餐"/><el-table-column label="状态"><template #default="s"><el-tag>{{userStatusText(s.row.status)}}</el-tag></template></el-table-column><el-table-column label="操作"><template #default="s"><el-button @click="toggle(s.row)">{{s.row.status==='active'?'停用':'启用'}}</el-button></template></el-table-column></el-table></div></template><script setup lang="ts">import{computed,onMounted,ref}from'vue';import PageHeader from'@/components/PageHeader.vue';import{adminApi}from'@/services/admin-api';import{filterRows,userStatusText}from'@/view-models';const rows=ref<any[]>([]),query=ref('');const filtered=computed(()=>filterRows(rows.value,query.value,['nickname','phone','id']));async function load(){rows.value=await adminApi.users()}async function toggle(x:any){await adminApi.setUserStatus(x.id,x.status==='active'?'disabled':'active');await load()}onMounted(load);</script>
